1:"Open Graph: Data de lan\303\247amento";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:31:"The date the book was released.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:25:"metatag-book_release_date";}s:14:"og_description";a:3:{s:4:"name";s:23:"Open Graph: Descri\303\247\303\243o";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:49:"A one to two sentence description of the content.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:22:"metatag-og_description";}s:13:"og_determiner";a:3:{s:4:"name";s:22:"Open Graph: Determiner";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:166:"The word that appears before the content''s title in a sentence. The default ignores this value, the ''Automatic'' value should be sufficient if this is actually needed.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:21:"metatag-og_determiner";}s:14:"video_director";a:3:{s:4:"name";s:23:"Open Graph: Director(s)";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:72:"Links to the Facebook profiles for director(s) that worked on the video.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:28:"list<metatag-video_director>";}s:17:"og_street_address";a:3:{s:4:"name";s:21:"Open Graph: Endere\303\247o";s:11:"description";s:0:"";s:4:"type";s:25:"metatag-og_street_address";}s:8:"og_email";a:3:{s:4:"name";s:31:"Open Graph: Endere\303\247o de e-mail";s:11:"description";s:0:"";s:4:"type";s:16:"metatag-og_email";}s:13:"og_fax_number";a:3:{s:4:"name";s:15:"Open Graph: Fax";s:11:"description";s:0:"";s:4:"type";s:21:"metatag-og_fax_number";}s:14:"profile_gender";a:3:{s:4:"name";s:19:"Open Graph: G\303\252nero";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:93:"Any of Facebook''s gender values should be allowed, the initial two being ''male'' and ''female''.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:22:"metatag-profile_gender";}s:9:"og_locale";a:3:{s:4:"name";s:18:"Open Graph: Idioma";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:101:"The locale these tags are marked up in, must be in the format language_TERRITORY. Default is ''en_US''.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:17:"metatag-og_locale";}s:12:"og_image_alt";a:3:{s:4:"name";s:33:"Open Graph: Image &#039;alt&#039;";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:119:"A description of what is in the image, not a caption. If the page specifies an og:image it should specify og:image:alt.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:20:"metatag-og_image_alt";}s:15:"og_image_height";a:3:{s:4:"name";s:24:"Open Graph: Image height";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:129:"The height of the above image(s). Note: if both the unsecured and secured images are provided, they should both be the same size.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:23:"metatag-og_image_height";}s:8:"og_image";a:3:{s:4:"name";s:18:"Open Graph: Imagem";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:435:"The URL of an image which should represent the content. The image must be at least 200 x 200 pixels in size; 600 x 316 pixels is a recommended minimum size, and for best results use an image least 1200 x 630 pixels in size. Supports PNG, JPEG and GIF formats. Should not be used if og:image:url is used. Note: if multiple images are added many services (e.g. Facebook) will default to the largest image, not specifically the first one.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:22:"list<metatag-og_image>";}s:19:"og_image_secure_url";a:3:{s:4:"name";s:28:"Open Graph: Image Secure URL";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:274:"The secure URL (HTTPS) of an image which should represent the content. The image must be at least 200 x 200 pixels in size; 600 x 316 pixels is a recommended minimum size, and for best results use an image least 1200 x 630 pixels in size. Supports PNG, JPEG and GIF formats.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:33:"list<metatag-og_image_secure_url>";}s:12:"og_image_url";a:3:{s:4:"name";s:21:"Open Graph: Image URL";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:99:"A alternative version of og:image and has exactly the same requirements; only one needs to be used.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:26:"list<metatag-og_image_url>";}s:14:"og_image_width";a:3:{s:4:"name";s:23:"Open Graph: Image width";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:128:"The width of the above image(s). Note: if both the unsecured and secured images are provided, they should both be the same size.";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:22:"metatag-og_image_width";}s:9:"book_isbn";a:3:{s:4:"name";s:16:"Open Graph: ISBN";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000string";s:15:"The Book''s ISBN";s:12:"\000*\000arguments";a:0:{}s:10:"\000*\000options";a:0:{}}s:4:"type";s:17:"metatag-book_isbn";}s:14:"og_video_width";a:3:{s:4:"name";s:29:"Open Graph: Largura do v\303\255deo";s:11:"description";O:48:"Drupal\\Core\\StringTranslation\\TranslatableMarkup":3:{s:9:"\000*\000s